SELECT COUNT(*) FROM ( SELECT pi.product_id, pi.lot_no, GREATEST( pi.inbound_qty - IFNULL(( SELECT SUM(po.outbound_qty) FROM product_outbound po WHERE po.product_id = pi.product_id AND po.lot_no = pi.lot_no ), 0), 0 ) AS stock_qty FROM product_inbound pi JOIN product p ON pi.product_id = p.product_id
(p.product_name LIKE CONCAT('%', #{keyword}, '%') OR pi.lot_no LIKE CONCAT('%', #{keyword}, '%'))
AND pi.reg_date >= #{startDate}
AND pi.reg_date <= #{endDate}
) AS tmp
stock_qty = 0
stock_qty < 50 AND stock_qty > 0
stock_qty >= 50

