SELECT '입고' AS type, pi.inbound_qty AS qty, pi.reg_date AS reg_date, NULL AS client_name, '' AS memo FROM product_inbound pi WHERE pi.product_id = #{productId} AND pi.lot_no = #{lotNo}
UNION ALL
SELECT '출고' AS type, po.outbound_qty AS qty, po.outbound_date AS reg_date, c.client_name AS client_name, '' AS memo FROM product_outbound po LEFT JOIN client c ON po.client_id = c.client_id WHERE po.product_id = #{productId} AND po.lot_no = #{lotNo}
ORDER BY reg_date ASC

SELECT COALESCE(SUM(reserved_qty), 0)
FROM stock_reservation
WHERE product_id = #{productId} AND lot_no = #{lotNo}

